/**
 * Execute a BigQuery query with retry logic and exponential backoff
 */
async function executeQueryWithRetry(query, maxRetries = 3) {
  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const options = {
        query: query,
        location: 'US',
        maximumBytesBilled: '10000000000', // 10GB limit per query
        useLegacySql: false,
        jobTimeoutMs: 300000 // 5 minute timeout per query job
      };

      const [job] = await bigquery.createQueryJob(options);
      console.log(`Query job ${job.id} started (attempt ${attempt}/${maxRetries})`);

      const [rows] = await job.getQueryResults({
        maxResults: 1000000,
        autoPaginate: true
      });

      return [rows];
    } catch (error) {
      lastError = error;
      console.warn(`Query attempt ${attempt}/${maxRetries} failed: ${error.message}`);

      if (attempt < maxRetries) {
        const backoffMs = Math.min(1000 * Math.pow(2, attempt), 30000);
        console.log(`Retrying in ${backoffMs}ms...`);
        await sleep(backoffMs);
      }
    }
  }

  throw lastError;
}

